{"windows":"// Place your key bindings in this file to override the defaultsauto[]
[
	{
		"key": "shift+oem_3",
		"command": "code-runner.run"
	},
	{
		"key": "ctrl+alt+n",
		"command": "-code-runner.run"
	}
]","linux":"// Place your key bindings in this file to override the defaultsauto[]
[
    {
        "key": "shift+`",
        "command": "code-runner.run"
    },
    {
        "key": "ctrl+alt+n",
        "command": "-code-runner.run"
    },
    {
        "key": "ctrl+;",
        "command": "peacock.darken"
    },
    {
        "key": "alt+meta+-",
        "command": "-peacock.darken"
    },
    {
        "key": "ctrl+;",
        "command": "peacock.enterColor"
    },
    {
        "key": "ctrl+;",
        "command": "peacock.docs"
    },
    {
        "key": "ctrl+;",
        "command": "peacock.changeColorToRandom"
    },
    {
        "key": "shift+alt+down",
        "command": "editor.action.copyLinesDownAction",
        "when": "editorTextFocus && !editorReadonly"
    },
    {
        "key": "ctrl+shift+alt+down",
        "command": "-editor.action.copyLinesDownAction",
        "when": "editorTextFocus && !editorReadonly"
    },
    {
        "key": "shift+alt+up",
        "command": "editor.action.copyLinesUpAction",
        "when": "editorTextFocus && !editorReadonly"
    },
    {
        "key": "ctrl+shift+alt+up",
        "command": "-editor.action.copyLinesUpAction",
        "when": "editorTextFocus && !editorReadonly"
    },
    {
        "key": "ctrl+o",
        "command": "workbench.action.files.openFolder",
        "when": "openFolderWorkspaceSupport"
    },
    {
        "key": "ctrl+k ctrl+o",
        "command": "-workbench.action.files.openFolder",
        "when": "openFolderWorkspaceSupport"
    },
    {
        "key": "ctrl+k shift+l",
        "command": "vscode-account.login"
    },
    {
        "key": "alt+f",
        "command": "editor.action.formatDocument",
        "when": "editorHasDocumentFormattingProvider && editorTextFocus && !editorReadonly && !inCompositeEditor"
    },
    {
        "key": "ctrl+shift+i",
        "command": "-editor.action.formatDocument",
        "when": "editorHasDocumentFormattingProvider && editorTextFocus && !editorReadonly && !inCompositeEditor"
    },
    {
        "key": "ctrl+alt+e",
        "command": "workbench.action.activityBarLocation.hide"
    },
    {
        "key": "ctrl+alt+w",
        "command": "workbench.action.activityBarLocation.default"
    },
    {
        "key": "ctrl+alt+q",
        "command": "editor.action.toggleMinimap"
    },
    {
        "key": "ctrl+alt+a",
        "command": "cursorHome",
        "when": "textInputFocus"
    },
    {
        "key": "home",
        "command": "-cursorHome",
        "when": "textInputFocus"
    }
]"}
